SELECT BIN_TO_UUID(reentries.id) AS reentry_id, BIN_TO_UUID(reentries.user_id) AS user_id, users.student_number AS student_number, user_profiles.username AS username, reentries.reentry_count, reentries.status, reentries.note, reentries.created_at, reentries.updated_at, CASE WHEN user_payments.id IS NULL THEN 'not_reported' WHEN user_payments.checked THEN 'approved' ELSE 'pending_accounting' END AS payment_status FROM reentries JOIN users ON users.id = reentries.user_id JOIN user_profiles ON user_profiles.user_id = reentries.user_id LEFT JOIN user_payments ON user_payments.user_id = reentries.user_id AND user_payments.year = /*year*/2024 WHERE reentries.status = 'pending' ORDER BY reentries.created_at ASC;
